import { useEffect, useReducer, useRef, useState } from 'react';
import {
  getTheme, setTheme, getColorBlind, setColorBlind,
  getHighContrast, setHighContrast,
  getMistakeMode, setMistakeMode,
  getReducedMotion, setReducedMotion,
  type ThemeChoice, type MistakeMode,
} from '../theme/theme';
import {
  isHapticsEnabled, setHapticsEnabled,
  isSoundsEnabled, setSoundsEnabled,
} from '../feedback';
import { useStore } from '../../state/store';
import { bus } from '../../lib/bus';
import { resetLifetimeStats } from '../../state/lifetime-stats';
import { trapFocus } from '../a11y/trap-focus';
import './settings.css';

interface Props { onClose: () => void; }

/**
 * Full settings sheet — focus-trapped, keyboard navigable. Replaces the brief
 * popover for users who want all knobs in one place.
 *
 * Lazy-loaded (so the boot bundle never carries this code).
 */
export function SettingsSheet({ onClose }: Props) {
  const sheetRef = useRef<HTMLDivElement>(null);
  const [, force] = useReducer(x => x + 1, 0);
  const [confirmReset, setConfirmReset] = useState(false);

  useEffect(() => {
    const n = sheetRef.current;
    if (!n) return;
    const release = trapFocus(n);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  function emitThemeChanged() {
    bus.emit('themeChanged', {
      mode: getTheme(),
      cb: getColorBlind(),
      hc: getHighContrast(),
    });
  }

  function pickTheme(c: ThemeChoice) { setTheme(c); emitThemeChanged(); force(); }
  function toggleCb()  { setColorBlind(!getColorBlind()); emitThemeChanged(); force(); }
  function toggleHc()  { setHighContrast(!getHighContrast()); emitThemeChanged(); force(); }
  function toggleRm()  { setReducedMotion(!getReducedMotion()); force(); }
  function toggleHap() { setHapticsEnabled(!isHapticsEnabled()); force(); }
  function toggleSnd() { setSoundsEnabled(!isSoundsEnabled()); force(); }
  function pickMistake(m: MistakeMode) {
    setMistakeMode(m);
    useStore.setState({ mistakeLimit: m === 'off' ? null : Number(m) });
    force();
  }
  function doResetStats() { resetLifetimeStats(); setConfirmReset(false); force(); }

  const t = getTheme();
  const cb = getColorBlind();
  const hc = getHighContrast();
  const rm = getReducedMotion();
  const mm = getMistakeMode();
  const hap = isHapticsEnabled();
  const snd = isSoundsEnabled();

  return (
    <div
      className="etch-settings-backdrop"
      role="dialog"
      aria-modal="true"
      aria-label="Settings"
      onClick={onClose}
    >
      <div
        className="etch-settings-sheet"
        ref={sheetRef}
        onClick={(e) => e.stopPropagation()}
      >
        <header>
          <h2>Settings</h2>
          <button onClick={onClose} aria-label="Close" className="etch-settings-close">×</button>
        </header>

        <section>
          <h3>Theme</h3>
          <div className="etch-settings-pills" role="radiogroup" aria-label="Theme">
            {(['light', 'dark', 'sepia', 'system'] as ThemeChoice[]).map(c => (
              <button
                key={c}
                role="radio"
                aria-checked={c === t}
                className={`etch-settings-pill${c === t ? ' is-selected' : ''}`}
                onClick={() => pickTheme(c)}
                type="button"
              >
                {c[0]!.toUpperCase() + c.slice(1)}
              </button>
            ))}
          </div>
        </section>

        <section>
          <h3>Display</h3>
          <label className="etch-settings-toggle">
            <input type="checkbox" checked={cb} onChange={toggleCb} />
            <span>Color-blind safe</span>
          </label>
          <label className="etch-settings-toggle">
            <input type="checkbox" checked={hc} onChange={toggleHc} />
            <span>High contrast</span>
          </label>
          <label className="etch-settings-toggle">
            <input type="checkbox" checked={rm} onChange={toggleRm} />
            <span>Reduced motion (override)</span>
          </label>
        </section>

        <section>
          <h3>Feedback</h3>
          <label className="etch-settings-toggle">
            <input type="checkbox" checked={snd} onChange={toggleSnd} />
            <span>Sound effects</span>
          </label>
          <label className="etch-settings-toggle">
            <input type="checkbox" checked={hap} onChange={toggleHap} />
            <span>Haptic feedback</span>
          </label>
        </section>

        <section>
          <h3>Hard mode (strikes)</h3>
          <div className="etch-settings-pills" role="radiogroup" aria-label="Hard mode">
            {(['off', '3', '5'] as MistakeMode[]).map(m => (
              <button
                key={m}
                role="radio"
                aria-checked={m === mm}
                className={`etch-settings-pill${m === mm ? ' is-selected' : ''}`}
                onClick={() => pickMistake(m)}
                type="button"
              >
                {m === 'off' ? 'Off' : `${m} strikes`}
              </button>
            ))}
          </div>
        </section>

        <section className="etch-settings-danger">
          <h3>Data</h3>
          {confirmReset ? (
            <div className="etch-settings-confirm">
              <span>Erase lifetime stats?</span>
              <button onClick={doResetStats} className="etch-settings-yes">Yes, erase</button>
              <button onClick={() => setConfirmReset(false)} className="etch-settings-no">Cancel</button>
            </div>
          ) : (
            <button
              type="button"
              onClick={() => setConfirmReset(true)}
              className="etch-settings-reset"
            >
              Reset lifetime stats
            </button>
          )}
        </section>
      </div>
    </div>
  );
}

export default SettingsSheet;
